STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_ALCOHOL = "Tăng sát thương và giảm tốc độ di chuyển trong một khoảng thời gian. Uống có chừng mực."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_ALCOHOL2 = "Tăng kháng sát thương và giảm tốc độ di chuyển trong một khoảng thời gian. Uống có chừng mực."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_RUM = "Tăng sát thương lên hải tặc trong một khoảng thời gian.\n\n\"Cả ngọn lửa lẫn vực sâu đều không thể nuốt chửng ta.\""
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_TEQUILA = "Dịch chuyển người sống sót đến một vị trí ngẫu nhiên trên bản đồ."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_NUKACOLA = "Hương vị độc nhất của Nuka-Cola là kết quả từ sự kết hợp của mười bảy tinh chất trái cây, được cân bằng để nâng tầm vị cola cổ điển. Đánh bay cơn khát!"
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_QUANTUM = "Hương vị độc nhất của Nuka-Cola là kết quả từ sự kết hợp của mười bảy tinh chất trái cây, được cân bằng để nâng tầm vị cola cổ điển. Đánh bay cơn khát!\n\nNuka-Cola Quantum có gấp đôi calo, gấp đôi carbohydrate, gấp đôi caffeine và gấp đôi hương vị!"
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_INSANITY = "Gây mất trí trong thời gian ngắn."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_NIGHTVISION = "Cho khả năng nhìn đêm trong một khoảng thời gian."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_NAUGHTY = "Ăn món ăn được làm từ một phần của linh hồn tội nghiệp và vô tội này sẽ khiến \"Hắn\" xuất hiện gần đó."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_HASTE = "Tăng tốc độ của mọi hành động được thực hiện trong một khoảng thời gian. Một số hành động sẽ không bị ảnh hưởng."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_BLOOM = "Một hỗn hợp phân trộn được ném chung vào nồi nấu, có thể kích thích sự nở rộ đến mức tối đa.\n\n\"Nghệ thuật!\" - Wormwood."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_SOUL = "Một món ăn đặc biệt được làm từ Linh Hồn đã thu hoạch.\n\nWortox có thể ăn món này để nhận lợi ích dựa trên thiên hướng Nghịch Ngợm và Ngoan Ngoãn của hắn."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_SOUL2 = "Một món ăn đặc biệt được làm từ Linh Hồn đã thu hoạch.\n\nWortox có thể ăn món này để nhận lợi ích dựa trên thiên hướng Nghịch Ngợm và Ngoan Ngoãn của hắn.\n\nTạm thời giảm nhiệt độ."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_DEERCLOPS = "Ăn món này sẽ khiến Deerclops xuất hiện gần đó."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_BEARGER = "Ăn món này sẽ khiến Bearger xuất hiện gần đó."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_FORTUNE = "Bẻ một cái để xem số mệnh đã dành sẵn điều gì cho ngươi."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_WATER = "Thanh tẩy mọi hiệu ứng phụ từ thức ăn đang hoạt động trên người sống sót.\nTạm thời giảm nhiệt độ."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_FROG = "Ăn món này sẽ khiến Ếch trở nên thân thiện với ngươi trong một khoảng thời gian."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_CURSE = "Woodie có thể ăn món này để ép bản thân biến hình ngẫu nhiên thành một dạng của mình."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_FEARLESS = "Món này có thể khiến người sống sót trở nên không biết sợ trong một khoảng thời gian. Các hào quang gây mất tinh thần sẽ không có tác dụng trong thời gian này."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_WURTFOOD = "Các người sống sót hệ quái vật có thể ăn món này mà không bị bất kỳ hình phạt nào.\nWurt sẽ nhận thêm lợi ích khi ăn món này."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_MONSTERFOOD = "Các người sống sót hệ quái vật có thể ăn món này mà không bị bất kỳ hình phạt nào."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_MONSTERFOOD2 = "Các người sống sót hệ quái vật có thể ăn món này mà không bị bất kỳ hình phạt nào.\nTạm thời giảm nhiệt độ."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_MONSTERFOOD3 = "Các người sống sót hệ quái vật có thể ăn món này mà không bị bất kỳ hình phạt nào.\nTạm thời tăng nhiệt độ."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_SPIDERCAKE = "Các người sống sót hệ quái vật có thể ăn món này mà không bị bất kỳ hình phạt nào.\n\nDon't Starve Together x Cult of the Lamb - Collab 2023."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_SUGARBOMBS = "Một gói ngũ cốc ngọt chứa 100% lượng đường khuyến nghị mỗi ngày. Bom Đường đã được bảo quản suốt 25 năm sau Đại Chiến. Tuy nhiên, điều đó cũng khiến phần lớn chúng bị nhiễm một chút phóng xạ."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_NUKASHINE = "Nukashine được Lewis của hội Eta Psi tại Đại học Vault-Tec tạo ra vào tháng 11 năm 2076. Loại rượu này cực kỳ mạnh, gây mất trí nhớ tạm thời, say bí tỉ nặng nề và có khả năng gây chết người, như hội Pi Mu đáng thương đã phát hiện ra trong \"bữa tiệc đuổi nhà\" của họ.\n\nMột phiên bản không đường cũng từng tồn tại, nhờ thiếu đường nên thức uống này có thể được dùng mà không có nguy cơ mất trí nhớ tạm thời."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_NUKASHINE2 = "Giờ không còn nguy cơ mất trí nhớ tạm thời! Tận hưởng bữa tiệc đi!"
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_BONESOUP = "Tăng sát thương lên sâu trong một khoảng thời gian."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_REVIVER = "Hồi sinh ngay lập tức một người chơi đã chết khi bị ám."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_MOCHA = "Tăng tốc độ di chuyển, khả năng kháng buồn ngủ và giảm tốc độ mất độ no trong một khoảng thời gian.\n\nTạm thời tăng nhiệt độ."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_LESSFREEZING = "Tạm thời tăng nhiệt độ và ít bị Đóng Băng hơn."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_LESSOVERHEAT = "Tạm thời giảm nhiệt độ và ít bị Quá Nhiệt hơn."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_FISHING = "Tăng sản lượng câu cá trong một khoảng thời gian."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_MIGHTINESS = "Tăng nhẹ sức mạnh cơ bắp."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_INSPIRATION = "Tăng nhẹ cảm hứng."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_WARLYTEA = "Giảm tốc độ mất tinh thần trong một khoảng thời gian.\nTạm thời tăng nhiệt độ."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_INCREASETEMP = "Tạm thời tăng nhiệt độ."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_DECREASETEMP = "Tạm thời giảm nhiệt độ."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_BOUILLABAISSE = "Tăng khả năng kháng buồn ngủ trong một khoảng thời gian.\nTạm thời giảm nhiệt độ."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_MOISTURE = "Làm khô người sống sót và cho miễn nhiễm với Độ Ẩm trong một khoảng thời gian."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_SUGARBOMBS_EXPLOSIVE = "Những Bom Đường này chứa đầy hương vị bùng nổ!"
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_EATER = "Làm thức ăn mềm hơn và dễ ăn hơn trong một khoảng thời gian."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_CRABKINGFEAST = "Tăng sát thương lên cua trong một khoảng thời gian."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_ANTLION = "Làm Antlion hài lòng trong một khoảng thời gian."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_JAWSBREAKER = "Dụ và giết Rockjaw cùng Gnarwail khi ném xuống đại dương. Không có tác dụng nếu ở quá gần."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_FIREIMMUNITY = "Món này có thể khiến người sống sót miễn nhiễm với Lửa trong một khoảng thời gian. Tạm thời tăng nhiệt độ."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_TIRAMISU = "Tăng tốc độ di chuyển trong một khoảng thời gian.\n\nLàm khô người sống sót và cho miễn nhiễm với Độ Ẩm trong một khoảng thời gian."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_AMPHIBIAN = "Tăng sát thương lên sinh vật lưỡng cư trong một khoảng thời gian."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_ENLIGHTENMENT = "Khai sáng người sống sót trong một khoảng thời gian."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_STEALTH = "Khiến người sống sót không bị nhìn thấy và không bị bẫy hay sinh vật phát hiện trong một khoảng thời gian."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_PLANARDEFENSE = "Tăng phòng thủ vị diện trong một khoảng thời gian."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_GOLDENAPPLE = "Cho nhiều hiệu ứng tích cực trong một khoảng thời gian, với cái giá là sinh mạng của ngươi. Hãy cẩn thận!\n\n\"Một báu vật cấm kỵ, được chúc phúc bởi cả thần linh lẫn thời gian. Những tia sáng lấp lánh che giấu cả ân sủng và đọa đày. Quyền năng không xiềng xích, còn linh hồn lắng nghe lời thì thầm của vĩnh hằng.\" - Tác Giả Vô Danh."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_PIGTRIBUTE = "Có thể dùng để kết bạn với Heo, khiến chúng trung thành lâu hơn.\nCó thể trao đổi với Vua Heo để lấy vài Cục Vàng."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_TRUFFLES = "Trong một khoảng thời gian, người sống sót sẽ trở nên không thể cưỡng lại với Heo, khiến chúng thân thiện.\n\nCó thể trao đổi với Vua Heo để lấy vài Cục Vàng."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_SPORECAP = "Món này có thể khiến người sống sót miễn nhiễm với Hào Quang Độc trong một khoảng thời gian.\n\nCác người sống sót hệ quái vật có thể ăn món này mà không bị bất kỳ hình phạt nào."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_SPORECAP2 = "Món này có thể khiến người sống sót miễn nhiễm với Hào Quang Độc trong một khoảng thời gian. Nó cũng làm tăng tốc độ hư hỏng của vật phẩm trong hành trang và ô trang bị.\n\nCác người sống sót hệ quái vật có thể ăn món này mà không bị bất kỳ hình phạt nào."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_SPORECAP_DARK = "Món này có thể khiến người sống sót miễn nhiễm với Mưa Axit trong một khoảng thời gian.\n\nCác người sống sót hệ quái vật có thể ăn món này mà không bị bất kỳ hình phạt nào."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_SPORECAP_DARK2 = "Món này có thể khiến người sống sót miễn nhiễm với Mưa Axit trong một khoảng thời gian. Nó cũng làm tăng tốc độ hư hỏng của vật phẩm trong hành trang và ô trang bị.\n\nCác người sống sót hệ quái vật có thể ăn món này mà không bị bất kỳ hình phạt nào."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_RAINBOWGLOW = "Phát ra ánh sáng khỏe khoắn đầy màu sắc trong thời gian ngắn."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_RAINBOWGLOW2 = "Phát ra ánh sáng khỏe khoắn đầy màu sắc trong một khoảng thời gian."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_RAINBOWGLOW3 = "Phát ra ánh sáng khỏe khoắn đầy màu sắc trong một khoảng thời gian. Tạm thời giảm nhiệt độ."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_RAINBOWGLOW4 = "Phát ra ánh sáng khỏe khoắn đầy màu sắc trong một khoảng thời gian. Tạm thời tăng nhiệt độ."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_PUFFERFISH = "Người sống sót phải cẩn thận khi ăn Cá Nóc. Nó có thể chứa độc nếu được nấu bởi đầu bếp non tay."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_EXQUISITE = "Một bữa ăn tinh tế và xa hoa.\nChắc chắn sẽ có ai đó thích món này làm quà."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_BLUBBER = "Giảm độ ẩm trên người sống sót."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_CURSE_MONKEY = "Món này có thể phá lời nguyền của Đảo Bến Trăng."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_CRAFTING = "Món này có thể khiến người sống sót chế thử và chế tạo vật phẩm mà không cần trạm chế tạo.\n\nMỗi vật phẩm được chế tạo sẽ tiêu hao một lượng nhỏ tinh thần."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_BEEFRIENDLY = "Ăn món này sẽ khiến Ong trở nên thân thiện với ngươi trong một khoảng thời gian."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_HOFBIRTHDAY_SLICE1 = "Tăng độ no tối đa thêm 15% trong một khoảng thời gian.\n\nMừng Kỷ Niệm 5 Năm Vua Đầu Bếp!"
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_HOFBIRTHDAY_SLICE2 = "Tăng máu tối đa thêm 15% trong một khoảng thời gian.\n\nMừng Kỷ Niệm 5 Năm Vua Đầu Bếp!"
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_HOFBIRTHDAY_SLICE3 = "Tăng tinh thần tối đa thêm 15% trong một khoảng thời gian.\n\nMừng Kỷ Niệm 5 Năm Vua Đầu Bếp!"
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_BERSERKER = "Tăng sát thương và giảm kháng sát thương trong một khoảng thời gian."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_HUNGERRATE = "Giảm tốc độ mất độ no trong một khoảng thời gian."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_DARKNESS = "Món này có thể khiến người sống sót không còn sợ bóng tối trong một khoảng thời gian."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_MAXHEALTH = "Tăng máu tối đa thêm 30% trong một khoảng thời gian."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_MAXHUNGER = "Tăng độ no tối đa thêm 30% trong một khoảng thời gian."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_MAXSANITY = "Tăng tinh thần tối đa thêm 30% trong một khoảng thời gian."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_NUKACOLA_DARK = "Tăng máu tối đa thêm 30% trong một khoảng thời gian.\nTạm thời giảm nhiệt độ."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODEFFECTS_NUKACOLA_TWIST = "Tăng máu, độ no và tinh thần tối đa thêm 15% trong một khoảng thời gian.\n\nTạm thời giảm nhiệt độ."

-- Spice Effects.
STRINGS.SCRAPBOOK.SPECIALINFO.SPICEEFFECTS_CURE = "Có thể được thêm vào món Nồi Nấu bằng Trạm Nêm Gia Vị Di Động.\n\nĂn món được nêm Bột Bảo Quản sẽ giảm một nửa tốc độ hư hỏng và loại bỏ hình phạt từ thức ăn hỏng."
STRINGS.SCRAPBOOK.SPECIALINFO.SPICEEFFECTS_MIND = "Có thể được thêm vào món Nồi Nấu bằng Trạm Nêm Gia Vị Di Động.\n\nĂn món được nêm Đường Xoa Dịu sẽ cho thêm 25% tinh thần."
STRINGS.SCRAPBOOK.SPECIALINFO.SPICEEFFECTS_FED = "Có thể được thêm vào món Nồi Nấu bằng Trạm Nêm Gia Vị Di Động.\n\nĂn món được nêm Tinh Bột No Nê sẽ cho thêm 25% độ no."
STRINGS.SCRAPBOOK.SPECIALINFO.SPICEEFFECTS_FIRE = "Có thể được thêm vào món Nồi Nấu bằng Trạm Nêm Gia Vị Di Động.\n\nĂn món được nêm Tinh Thể Lửa sẽ khiến đòn tấn công của ngươi đốt cháy mục tiêu.\n\nKéo dài 4 phút.\n\nĐồng thời tăng nhiệt độ thêm 15 độ trong 15 giây."
STRINGS.SCRAPBOOK.SPECIALINFO.SPICEEFFECTS_COLD = "Có thể được thêm vào món Nồi Nấu bằng Trạm Nêm Gia Vị Di Động.\n\nĂn món được nêm Vảy Băng sẽ khiến đòn tấn công của ngươi đóng băng mục tiêu.\n\nKéo dài 4 phút.\n\nĐồng thời giảm nhiệt độ 15 độ trong 15 giây."

-- Items & Foods.
STRINGS.SCRAPBOOK.SPECIALINFO.SALT = "Dùng một nhúm muối lên món Nồi Nấu sẽ làm mới thời gian hư hỏng của nó thêm 30%. Đừng lo phải ăn lại mấy món ôi nữa!"
STRINGS.SCRAPBOOK.SPECIALINFO.SALTRACK = "Chiếc giá này sẽ thu được một viên muối nhỏ sau mỗi vài ngày."
STRINGS.SCRAPBOOK.SPECIALINFO.CRABTRAP = "Sau khi đặt xuống đất, nó sẽ kích hoạt khi có cua di chuyển gần đó và bắt chúng lại.\n\nThu nhặt chiếc bẫy đã bắt được con mồi sẽ đưa sinh vật bên trong vào hành trang của ngươi.\n\nBẫy Cua có thể được mồi bằng thịt."
STRINGS.SCRAPBOOK.SPECIALINFO.CARAMELCUBE = "Món này là một cao lương mỹ vị, một khối ngọt ngào và yêu thương tinh khiết đông đặc. Đây là mục đặc biệt dành cho ai nghiện đường, cực kỳ, cực kỳ được người lớn tuổi ưa chuộng."
STRINGS.SCRAPBOOK.SPECIALINFO.NECTAR = "Ong đã thụ phấn đủ hoa sẽ rơi ra mật hoa khi bị giết.\n\nMật Hoa sẽ được chuyển hóa thành Mật Ong khi cất trong Kho Chứa Mật."
STRINGS.SCRAPBOOK.SPECIALINFO.BOTTLESOUL = "Linh Hồn Trong Chai không được tính vào tổng số Linh Hồn trong hành trang của Wortox."
STRINGS.SCRAPBOOK.SPECIALINFO.BOTTLECAP = "Những chiếc nắp chai bền bỉ, tiện mang theo và nhìn là nhận ra ngay từ Tập Đoàn Nuka-Cola!"
STRINGS.SCRAPBOOK.SPECIALINFO.CANNEDFOOD = "Một nguồn thức ăn khẩn cấp đáng tin cậy. Nó sẽ không bao giờ hỏng trừ khi ngươi mở ra!"
STRINGS.SCRAPBOOK.SPECIALINFO.BREWBOOK = "Ghi chép về tất cả đồ uống đã được ủ và/hoặc đã uống, cũng như các nguyên liệu dùng để ủ chúng."
STRINGS.SCRAPBOOK.SPECIALINFO.BUCKET = "Xô có thể dùng để lấy sữa từ động vật.\n\nHãy cẩn thận vì một vài con có thể nổi giận khi ngươi thử làm vậy. Nhớ luôn mặc đồ bảo hộ.\n\nLấy sữa từ động vật đã thuần hóa sẽ dễ hơn, vì chúng cho nhiều đơn vị sữa hơn và không làm hại ngươi."
STRINGS.SCRAPBOOK.SPECIALINFO.COOKWARE_HANGER_ITEM = "Móc treo này có thể được lắp phía trên Hố Lửa để giữ nồi nấu."
STRINGS.SCRAPBOOK.SPECIALINFO.COOKWARE_POT_ITEM = "Nồi nấu này cần một móc treo được đặt phía trên Hố Lửa."
STRINGS.SCRAPBOOK.SPECIALINFO.COOKWARE_OVEN_ITEM = "Lò nướng này có thể được lắp trên Hố Lửa để đặt khay hầm vào bên trong."
STRINGS.SCRAPBOOK.SPECIALINFO.COOKWARE_CASSEROLE_ITEM = "Khay hầm này cần một lò nướng được đặt trên Hố Lửa."
STRINGS.SCRAPBOOK.SPECIALINFO.COOKWARE_GRILL_ITEM = "Bếp nướng này có thể được lắp trên Hố Lửa để chế biến thức ăn."
STRINGS.SCRAPBOOK.SPECIALINFO.HUMANMEAT = "Chiến dịch có thể chờ, lúc này cuộc tàn sát đang vẫy gọi.\n\nLog Ping có thể được thu hoạch từ xác của những người sống sót đồng hành."
STRINGS.SCRAPBOOK.SPECIALINFO.MUSSELSTICK_ITEM = "Có thể đặt xuống nước để bắt vẹm theo thời gian."
STRINGS.SCRAPBOOK.SPECIALINFO.REPAIRTOOLKIT = "Dùng để sửa các công trình đã bị phá hủy."
STRINGS.SCRAPBOOK.SPECIALINFO.SAPBUCKET = "Gắn nó vào Cây Gỗ Đường để tạo ra Nhựa Cây tươi sau mỗi vài ngày."
STRINGS.SCRAPBOOK.SPECIALINFO.SLAUGHTERTOOL = "Dụng cụ làm thịt có thể giết động vật ngay lập tức."
STRINGS.SCRAPBOOK.SPECIALINFO.SAPHEALER = "Thuốc giải cực mạnh có khả năng chữa lành cho cây.\n\nDùng nó lên Cây Gỗ Đường Đổ Nát sẽ đưa chúng trở lại trạng thái bình thường."
STRINGS.SCRAPBOOK.SPECIALINFO.ITEMSLICER = "Dùng để cắt lát khối thịt và những thứ khác."
STRINGS.SCRAPBOOK.SPECIALINFO.ITEMSLICER2 = "Dùng để cắt lát khối thịt và những thứ khác, nhanh hơn!"
STRINGS.SCRAPBOOK.SPECIALINFO.SAMMYHAT = "Giảm tốc độ mất độ no 15%."
STRINGS.SCRAPBOOK.SPECIALINFO.POTATOSACK = "Một túi chứa 6 ô có thể cất các vật phẩm liên quan đến khoai tây và giữ chúng tươi lâu hơn.\n\n\"Khoai tây mạnh cho bụng!\" - Wolfgang."
STRINGS.SCRAPBOOK.SPECIALINFO.FOODSACK = "Một túi chứa chống nước 8 ô, giữ nguyên liệu của ngươi tươi ngon bất chấp thời tiết.\n\nThiết kế khéo léo của nó không chỉ làm chậm hư hỏng, mà còn có thể phục hồi độ tươi cho nguyên liệu đã bắt đầu hỏng.\n\nNó rung lên với sức mạnh băng giá ma thuật, đóng băng mọi thứ bên trong."
STRINGS.SCRAPBOOK.SPECIALINFO.BOOK_GARDENING = "Làm lớn nhanh mọi loại cây gần đó.\n\n\"Một cổ thư được bọc bằng rễ sống, bị lưu đày vì quyền năng áp đảo có thể bẻ cong ý chí của tự nhiên. Những trang sách thì thầm các lời lẽ bị lãng quên, có thể đánh thức chính mặt đất, biến đất thường thành hoang dã sống động không thể thuần hóa.\" - Tác Giả Vô Danh."
STRINGS.SCRAPBOOK.SPECIALINFO.FISHFARMPLOTKIT = "Bản thiết kế nền móng cho Trại Ươm Cá."
STRINGS.SCRAPBOOK.SPECIALINFO.MALBATROSSFOOD = "Thu hút Malbatross khi ném xuống đại dương."
STRINGS.SCRAPBOOK.SPECIALINFO.OCEANTRAP = "Sau khi đặt trên đại dương, nó sẽ kích hoạt khi có cá di chuyển gần đó và bắt chúng lại.\n\nThu nhặt chiếc bẫy đã bắt được con mồi sẽ đưa sinh vật bên trong vào hành trang của ngươi.\n\nBẫy Đại Dương có thể được mồi bằng thức ăn phù hợp."
STRINGS.SCRAPBOOK.SPECIALINFO.DRYAGAIN = "Để nó phơi khô lâu hơn sẽ tiếp tục nâng cao chất lượng."
STRINGS.SCRAPBOOK.SPECIALINFO.HOFBIRTHDAY_CANDLE = "Dùng nó để thắp sáng Bánh Kỷ Niệm và bắt đầu bữa tiệc!"
STRINGS.SCRAPBOOK.SPECIALINFO.HOFBIRTHDAY_HAT5 = "Cho phép thu thập Niềm Vui Kỷ Niệm.\n\nMừng Kỷ Niệm 5 Năm Vua Đầu Bếp!"
STRINGS.SCRAPBOOK.SPECIALINFO.HOFBIRTHDAY_SAMMYHAT = "Chiếc mũ kỷ niệm đặc biệt của Sammy.\nCho phép nhận Niềm Vui Kỷ Niệm.\n\nMừng Kỷ Niệm 5 Năm Vua Đầu Bếp!"
STRINGS.SCRAPBOOK.SPECIALINFO.FISHREGISTRYHAT = "Nghiên cứu cá và trứng cá sẽ thêm chúng vào Sổ Cá."
STRINGS.SCRAPBOOK.SPECIALINFO.CHICKENEGG_LARGE = "Một quả trứng quá khổ có thể ném hoặc ấp nở.\n\nGiảm sát thương và tốc độ di chuyển của mục tiêu 10% trong 20 giây. Hiệu ứng cộng dồn tối đa 3 lần, tổng cộng 30%.\n\n\"Ngay cả trứng cũng là vũ khí trên chiến trường!\" - Wigfrid."
STRINGS.SCRAPBOOK.SPECIALINFO.CHICKENEGG_CRACKED = "Có thể được ấp nở khi ở gần nguồn nhiệt."
STRINGS.SCRAPBOOK.SPECIALINFO.HERMITCRABTEA_ALOE = "Chăm sóc vết thương và làm mát bản thân bằng món trà được Pearl pha đầy yêu thương này."
STRINGS.SCRAPBOOK.SPECIALINFO.HERMITCRABTEA_SUGARTREE_PETALS = "Xoa dịu tâm trí và bảo vệ nó trước những kẻ thù đáng sợ bằng món trà được Pearl pha đầy yêu thương này."

-- Creatures.
STRINGS.SCRAPBOOK.SPECIALINFO.CHICKEN = "Khẩu phần của chúng chủ yếu gồm Hạt Giống, Lúa Mì hoặc Nhánh Đốm.\n\nGà tìm thấy ngoài hoang dã có 40% cơ hội đẻ Trứng sau khi ăn. Chúng có một cơ hội nhỏ đẻ Trứng Lớn.\n\nGà sống trong Chuồng có thể đẻ Trứng mỗi ngày sau khi ăn. Chúng có cơ hội đẻ Trứng Lớn cao hơn."
STRINGS.SCRAPBOOK.SPECIALINFO.PIKO = "Những người bạn nhỏ lông xù rất thích trộm những món quý giá nhất của ngươi!"
STRINGS.SCRAPBOOK.SPECIALINFO.KINGFISHER = "Chim Bói Cá thường sẽ thả Cá Koi Nhiệt Đới từ trên cao xuống. Mưa cá, đúng nghĩa đấy!"
STRINGS.SCRAPBOOK.SPECIALINFO.JELLYFISH_RAINBOW = "Phát ra ánh sáng khỏe khoắn đầy màu sắc vào hoàng hôn và ban đêm."
STRINGS.SCRAPBOOK.SPECIALINFO.HULLBREAKER_CREATURE = "Có thể làm hỏng thân Thuyền khi tấn công trúng."
STRINGS.SCRAPBOOK.SPECIALINFO.PACKIMBAGGIMS = "Có thể cất đồ trong Packim Baggims giống như một chiếc rương.\n\nNó thích ăn đủ loại cá."

-- Structures, Misc & Point of Interest.
STRINGS.SCRAPBOOK.SPECIALINFO.PIGELDER = "Một thương nhân đến từ quần đảo xa xôi. Ông ấy sẵn lòng trao đổi những dụng cụ nấu ăn tốt nhất và các vật phẩm hữu ích khác để lấy những bữa ăn ngon.\n\nTrưởng Lão đang thèm một món cực kỳ ngọt hoặc Bơ trộn với hải sản. Ông ấy sẽ thưởng cho ngươi xứng đáng.\n\nMang đến món khoái khẩu của Trưởng Lão sẽ mở khóa thêm nhiều giao dịch hơn."
STRINGS.SCRAPBOOK.SPECIALINFO.SAMMY = "Một thương nhân đến từ cõi giới khác. Bằng cách nào đó, anh ta bị mắc kẹt trên một trong những hòn đảo của The Constant và tạm thời dựng một cửa hiệu để đổi chác.\n\nSammy trao đổi đủ loại vật phẩm hiếm xuyên suốt các mùa và trong vài dịp đặc biệt. Nhớ kiểm tra hàng hóa của anh ta thỉnh thoảng để xem anh ta có gì.\n\nSammy sẽ thưởng hậu hĩnh nếu ngươi mang đến một món quà khiến anh ta nhớ nhà."
STRINGS.SCRAPBOOK.SPECIALINFO.SAMMYHOUSE = "Cửa Hiệu của Sammy chứa đủ loại vật phẩm kỳ lạ và đồ cổ từ những vùng đất xa xôi cùng các cõi giới khác."
STRINGS.SCRAPBOOK.SPECIALINFO.SAMMYWAGON = "Chiếc xe hàng Sammy vô cùng trân quý. Đừng để kích thước của nó đánh lừa ngươi, bên trong có thể chứa rất nhiều thứ."
STRINGS.SCRAPBOOK.SPECIALINFO.SALTPOND = "Những ao nước giàu muối. Có thể lắp Giá Muối để dễ dàng thu được đá muối sau mỗi vài ngày."
STRINGS.SCRAPBOOK.SPECIALINFO.MEALGRINDER = "Đứng gần thiết bị này sẽ cho người sống sót những nguyên liệu mới mà họ có thể nghiền.\n\nNgươi cần đứng gần Cối Nghiền mỗi khi muốn nghiền một nguyên liệu mới."
STRINGS.SCRAPBOOK.SPECIALINFO.PIKOTREE = "Đứng gần cây sẽ cho 35% khả năng che mưa và làm mát người sống sót một chút.\n\nNhững Cây Trà này bị những sinh vật nhỏ gọi là Piko gây nhiễm, và chúng đã sẵn sàng gây rối."
STRINGS.SCRAPBOOK.SPECIALINFO.ANTCHEST = "Chiếc rương đặc biệt này chỉ có thể chứa các vật phẩm làm từ mật ong, tối đa 7 vật phẩm cùng lúc. Nó cũng phát ra ánh sáng khỏe khoắn.\n\nNếu thức ăn làm từ mật ong được cất bên trong, chiếc rương sẽ làm mới thời gian hư hỏng của chúng và giữ chúng tươi mãi mãi.\n\nMật Hoa cất bên trong cuối cùng sẽ chuyển thành Mật Ong."
STRINGS.SCRAPBOOK.SPECIALINFO.BREWER = "Một vật chứa 3 ô dùng để nhận nguyên liệu ủ.\n\nĐặt 3 vật phẩm vào vật chứa sẽ cho phép chúng được ủ, tạo ra một loại thức ăn nào đó tùy theo các vật phẩm được cho vào ban đầu.\n\nQuá trình này thường mất vài ngày để hoàn thành."
STRINGS.SCRAPBOOK.SPECIALINFO.COOKWARE_HANGER = "Dùng để giữ một nồi nấu."
STRINGS.SCRAPBOOK.SPECIALINFO.COOKWARE_POT_SMALL = "Một vật chứa 3 ô dùng để nhận nguyên liệu nấu ăn.\n\nĐặt 3 vật phẩm vào vật chứa sẽ cho phép chúng được nấu, tạo ra một loại thức ăn nào đó tùy theo các vật phẩm được cho vào ban đầu.\n\nNồi nấu này nấu nhanh hơn nồi thường và có cơ hội cho thêm một phần món ăn đã nấu."
STRINGS.SCRAPBOOK.SPECIALINFO.COOKWARE_POT = "Một vật chứa 4 ô dùng để nhận nguyên liệu nấu ăn.\n\nĐặt 4 vật phẩm vào vật chứa sẽ cho phép chúng được nấu, tạo ra một loại thức ăn nào đó tùy theo các vật phẩm được cho vào ban đầu.\n\nNồi nấu này nấu nhanh hơn nồi thường và cho thêm một phần món ăn đã nấu."
STRINGS.SCRAPBOOK.SPECIALINFO.COOKWARE_SYRUP_POT = "Một vật chứa 4 ô dùng để nhận nguyên liệu làm Xi-rô.\n\nĐặt 4 Nhựa Cây vào vật chứa sẽ cho phép chúng được nấu thành Xi-rô.\n\nNồi này chỉ có thể nấu Xi-rô và cho thêm 3 phần."
STRINGS.SCRAPBOOK.SPECIALINFO.COOKWARE_OVEN = "Dùng để đặt khay hầm vào bên trong."
STRINGS.SCRAPBOOK.SPECIALINFO.COOKWARE_CASSEROLE_SMALL = "Một vật chứa 3 ô dùng để nhận nguyên liệu nấu ăn.\n\nĐặt 3 vật phẩm vào vật chứa sẽ cho phép chúng được nấu, tạo ra một loại thức ăn nào đó tùy theo các vật phẩm được cho vào ban đầu.\n\nNồi nấu này nấu nhanh hơn nồi thường và có cơ hội giữ lại một trong các nguyên liệu đã dùng."
STRINGS.SCRAPBOOK.SPECIALINFO.COOKWARE_CASSEROLE = "Một vật chứa 4 ô dùng để nhận nguyên liệu nấu ăn.\n\nĐặt 4 vật phẩm vào vật chứa sẽ cho phép chúng được nấu, tạo ra một loại thức ăn nào đó tùy theo các vật phẩm được cho vào ban đầu.\n\nNồi nấu này nấu nhanh hơn nồi thường và giữ lại một trong các nguyên liệu đã dùng."
STRINGS.SCRAPBOOK.SPECIALINFO.COOKWARE_GRILL_SMALL = "Một vật chứa 3 ô dùng để nhận nguyên liệu nấu ăn.\n\nĐặt 3 vật phẩm vào vật chứa sẽ cho phép chúng được nấu, tạo ra một loại thức ăn nào đó tùy theo các vật phẩm được cho vào ban đầu.\n\nNồi nấu này nấu nhanh hơn nồi thường và tạo ra món ăn đã nấu còn tươi."
STRINGS.SCRAPBOOK.SPECIALINFO.COOKWARE_GRILL = "Một vật chứa 4 ô dùng để nhận nguyên liệu nấu ăn.\n\nĐặt 4 vật phẩm vào vật chứa sẽ cho phép chúng được nấu, tạo ra một loại thức ăn nào đó tùy theo các vật phẩm được cho vào ban đầu.\n\nNồi nấu này nấu nhanh hơn nồi thường và tạo ra món ăn đã nấu còn tươi."
STRINGS.SCRAPBOOK.SPECIALINFO.KOKONUTTREE = "Đứng gần cây sẽ cho 35% khả năng che mưa và làm mát người sống sót một chút.\n\nCẩn thận Dừa rơi!"
STRINGS.SCRAPBOOK.SPECIALINFO.MUSSELSTICK = "Chiếc que này hấp dẫn vẹm đến không cưỡng lại được, cứ để nó đó một lúc rồi nó sẽ đầy vẹm cho ngươi thu hoạch."
STRINGS.SCRAPBOOK.SPECIALINFO.MUSHSTUMP = "Gốc cây này mọc một loại nấm đặc biệt, được nhiều người xem là cao lương mỹ vị.\n\nNó mất gần 5 ngày để phát triển."
STRINGS.SCRAPBOOK.SPECIALINFO.SUGARTREE = "Đứng gần cây sẽ cho 35% khả năng che mưa và làm mát người sống sót một chút.\n\nNhững cây này có thể được gắn vòi bằng Bộ Gắn Vòi Cây để tạo ra Nhựa Cây tươi sau mỗi vài ngày."
STRINGS.SCRAPBOOK.SPECIALINFO.SUGARTREE_SAPPED = "Đứng gần cây sẽ cho 35% khả năng che mưa và làm mát người sống sót một chút.\n\nMất gần 3 ngày để tạo ra Nhựa Cây.\n\nĐừng để Nhựa Cây tràn đầy, nếu không cây sẽ bị hỏng."
STRINGS.SCRAPBOOK.SPECIALINFO.SUGARTREE_RUINED = "Đứng gần cây sẽ cho 35% khả năng che mưa và làm mát người sống sót một chút.\n\nCây Gỗ Đường Đổ Nát không thể tạo ra Nhựa Cây tươi, thay vào đó chúng sẽ tạo ra Nhựa Cây Hỏng.\n\nNgươi có thể chữa lành cây bị hỏng bằng Thuốc Giải Mốc."
STRINGS.SCRAPBOOK.SPECIALINFO.SUGARTREE_RUINED2 = "Đứng gần cây sẽ cho 35% khả năng che mưa và làm mát người sống sót một chút.\n\nNgươi có thể chữa lành cây bị hỏng bằng Thuốc Giải Mốc."
STRINGS.SCRAPBOOK.SPECIALINFO.RUBBLE = "Trưởng Lão muốn ngươi giúp sửa chiếc Nồi Cũ của ông ấy để ông có thể bắt đầu làm Xi-rô thơm ngon trở lại."
STRINGS.SCRAPBOOK.SPECIALINFO.PINEAPPLEBUSH = "Bụi Dứa mất gần 6 ngày để phát triển hoàn toàn. Chúng lớn chậm hơn trong mọi mùa, trừ Mùa Hè.\n\nTrong Mùa Hè, chúng sẽ bắt đầu phát triển mỗi 2 ngày."
STRINGS.SCRAPBOOK.SPECIALINFO.GARDENSPRINKLER = "Có thể bật và tắt. Khi được nạp nhiên liệu và bật lên, nó sẽ tự động tưới các cây trồng nông trại trong phạm vi."
STRINGS.SCRAPBOOK.SPECIALINFO.FARMPLOT = "Cho phép trồng và phát triển Hạt Giống.\n\nHạt giống đã trồng sẽ phát triển ngẫu nhiên thành một loại cây trồng. Có thể trồng cây cụ thể bằng cách dùng Hạt Giống Cây Trồng.\n\nRuộng sẽ cạn kiệt sau một số lần thu hoạch, và cần được bón phân để trồng thêm cây. Cây đang phát triển có thể được bón phân để lớn nhanh hơn.\n\nViệc bón phân này chỉ ảnh hưởng đến cây trồng, và sẽ không ảnh hưởng đến trạng thái màu mỡ của chính Ruộng."
STRINGS.SCRAPBOOK.SPECIALINFO.SURFACEBANANATREE = "Một loài cây ngoại lai quý hiếm và khó tìm, có thể phát triển bên ngoài môi trường dưới lòng đất.\n\nNgười ta nói nó đã tuyệt chủng trong tự nhiên, chỉ còn vài cây được những người chăm sóc chuyên môn giữ gìn."
STRINGS.SCRAPBOOK.SPECIALINFO.PARTITIO = "Một thương nhân heo kiêu hãnh sống trong Rừng Rụng Lá, luôn háo hức trao đổi hàng hóa của mình lấy những vật phẩm giá trị.\n\nDù có thái độ kiêu ngạo và đầy cạnh tranh, anh ta vẫn trân trọng những khách hàng trung thực và không bao giờ bỏ lỡ cơ hội để thực hiện một vụ giao dịch tốt.\n\nTuy nhiên, sau vài sự kiện không may trong quá khứ, anh ta từ chối làm ăn với Người Cá trong bất kỳ hoàn cảnh nào."
STRINGS.SCRAPBOOK.SPECIALINFO.PARTITIOHOUSE = "Kho Hàng của Partitio bán nhiều loại sản phẩm khác nhau, chủ yếu là cây giống ăn quả và nhiều loại cây trồng khác."
STRINGS.SCRAPBOOK.SPECIALINFO.ITEMSHOWCASER = "Một công trình dùng để trưng bày các món ăn đã chuẩn bị."
STRINGS.SCRAPBOOK.SPECIALINFO.FISHFARMPLOT = "Một vật chứa 8 ô dùng để nhận cá nhằm nhân giống.\n\nĐặt một con cá vào ô đầu tiên và cho nó ăn sẽ cho phép nhân giống. Cá sẽ tạo ra cá con và trứng cá tương ứng sau khi một khoảng thời gian nhất định trôi qua.\n\nCá chỉ có thể sinh sản khi thỏa mãn mọi điều kiện của chúng, mỗi loài cá có sở thích riêng, chẳng hạn như: Giai Đoạn Ngày, Pha Trăng, Mùa và Vị Trí."
STRINGS.SCRAPBOOK.SPECIALINFO.OCEANHUNT = "Một vệt bong bóng cho thấy có hoạt động dưới nước.\nĐi theo dấu vết có thể dẫn ngươi đến sinh vật đứng sau chúng."
STRINGS.SCRAPBOOK.SPECIALINFO.WHALEOCEANCARCASS = "Một xác cá voi đã bắt đầu thối rữa.\n\nNó sẽ ngày càng phình to hơn mỗi ngày cho đến khi phát nổ và giải phóng mọi thứ bên trong.\n\nÂm thanh vụ nổ có thể thu hút sự chú ý không mong muốn."
STRINGS.SCRAPBOOK.SPECIALINFO.OCTOPUSKINGTRADER = "Một con bạch tuộc cô độc sống giữa đại dương rộng lớn.\n\nYaarctopus trao phần thưởng để đổi lấy Cá, Đồ Lặt Vặt và một số Món Cá Đã Nấu."
STRINGS.SCRAPBOOK.SPECIALINFO.OCTOPUSKINGTREASURE = "Chiếc rương của Yaarctopus được trao cho những người sống sót trong các cuộc trao đổi của họ."
STRINGS.SCRAPBOOK.SPECIALINFO.PACKIMBAGGIMS_FISHBONE = "Triệu hồi Packim Baggims khi được nhặt lên.\n\nPackim Baggims sẽ đi theo người cầm nó. Khi Packim Baggims còn sống, màu của cá sẽ là cam."
STRINGS.SCRAPBOOK.SPECIALINFO.HOFBIRTHDAY = "Mừng Kỷ Niệm 5 Năm Vua Đầu Bếp!"
STRINGS.SCRAPBOOK.SPECIALINFO.HOFBIRTHDAY_CAKE = "Có thể được cắt lát bằng Dao Phay để nhận Lát Bánh Kỷ Niệm. Mỗi Lát có hương vị và hiệu ứng khác nhau.\n\nTăng tinh thần của những người sống sót xung quanh theo thời gian.\n\nMừng Kỷ Niệm 5 Năm Vua Đầu Bếp!"
STRINGS.SCRAPBOOK.SPECIALINFO.HOFBIRTHDAY_BALLOONS = "Tăng tinh thần của những người sống sót xung quanh theo thời gian.\n\nMừng Kỷ Niệm 5 Năm Vua Đầu Bếp!"
STRINGS.SCRAPBOOK.SPECIALINFO.HOFBIRTHDAY_POPCORNMACHINE = "Một vật chứa 2 ô dùng để nhận bắp nhằm làm bắp rang.\n\nĐặt bắp vào ô đầu tiên sẽ cho phép tạo ra 5 phần bắp rang.\n\nTrong Dịp Kỷ Niệm Vua Đầu Bếp, nó sẽ tạo ra Bắp Rang Kỷ Niệm thay vào đó.\n\nMừng Kỷ Niệm 5 Năm Vua Đầu Bếp!"
STRINGS.SCRAPBOOK.SPECIALINFO.ANIMALFEEDER = "Một số động vật sẽ ăn từ lượng thức ăn được tích trữ trong máng này.\n\nHạt Giống và Ngũ Cốc có thể được dùng làm nguồn thức ăn chính."
STRINGS.SCRAPBOOK.SPECIALINFO.CHICKENHOUSE = "Một nơi trú ẩn cho Gà, có thể tạo ra các sản phẩm gia cầm."
STRINGS.SCRAPBOOK.SPECIALINFO.DAILYRECIPE_SIGN = "Theo dõi Công Thức Hôm Nay và cho phép xem lại nhanh chúng."